document.addEventListener("DOMContentLoaded",function(){const valoresPlanos={corrida:{essencial:{mensal:240,trimestral:660,semestral:1200},premium:{mensal:320,trimestral:915,semestral:1740}},triathlon:{essencial:{mensal:380,trimestral:1080,semestral:2040},premium:{mensal:420,trimestral:1200,semestral:2280}}};const valoresEquivalentes={corrida:{essencial:{trimestral:220,semestral:200},premium:{trimestral:305,semestral:290}},triathlon:{essencial:{trimestral:360,semestral:340},premium:{trimestral:400,semestral:380}}};const filtroModalidade=document.querySelectorAll(".filtro-modalidade");const filtroPeriodo=document.querySelectorAll(".filtro-periodo");let modalidadeAtual="corrida";let periodoAtual="mensal";function atualizarPrecos(){const essencialMensal=document.getElementById("essencial-mensal-preco");const essencialTrimestral=document.getElementById("essencial-trimestral-preco");const essencialSemestral=document.getElementById("essencial-semestral-preco");const premiumMensal=document.getElementById("premium-mensal-preco");const premiumTrimestral=document.getElementById("premium-trimestral-preco");const premiumSemestral=document.getElementById("premium-semestral-preco");if(essencialMensal)essencialMensal.textContent=valoresPlanos[modalidadeAtual].essencial.mensal;if(essencialTrimestral)essencialTrimestral.textContent=valoresPlanos[modalidadeAtual].essencial.trimestral;if(essencialSemestral)essencialSemestral.textContent=valoresPlanos[modalidadeAtual].essencial.semestral;if(premiumMensal)premiumMensal.textContent=valoresPlanos[modalidadeAtual].premium.mensal;if(premiumTrimestral)premiumTrimestral.textContent=valoresPlanos[modalidadeAtual].premium.trimestral;if(premiumSemestral)premiumSemestral.textContent=valoresPlanos[modalidadeAtual].premium.semestral;atualizarLinks()}function mostrarPeriodo(){const periodoCards=document.querySelectorAll(".periodo-card");periodoCards.forEach(card=>{const cardPeriodo=card.getAttribute("data-periodo");if(cardPeriodo===periodoAtual){card.style.display="block";card.classList.add("ativo")}else{card.style.display="none";card.classList.remove("ativo")}})}function atualizarLinks(){const treinadorNome=document.querySelector(".bio-nome").textContent.toLowerCase().replace(" ","-");const essencialLinks=document.querySelectorAll('[class*="essencial-link"]');essencialLinks.forEach(link=>{const periodo=link.getAttribute("data-periodo")||periodoAtual;link.href=`../cadastro-unificado.html?modalidade=${modalidadeAtual}&plano=essencial&treinador=${treinadorNome}&periodo=${periodo}`});const premiumLinks=document.querySelectorAll('[class*="premium-link"]');premiumLinks.forEach(link=>{const periodo=link.getAttribute("data-periodo")||periodoAtual;link.href=`../cadastro-unificado.html?modalidade=${modalidadeAtual}&plano=premium&treinador=${treinadorNome}&periodo=${periodo}`})}filtroModalidade.forEach(filtro=>{filtro.addEventListener("click",function(){filtroModalidade.forEach(f=>f.classList.remove("ativo"));this.classList.add("ativo");modalidadeAtual=this.getAttribute("data-modalidade");atualizarPrecos()})});filtroPeriodo.forEach(filtro=>{filtro.addEventListener("click",function(){filtroPeriodo.forEach(f=>f.classList.remove("ativo"));this.classList.add("ativo");periodoAtual=this.getAttribute("data-periodo");mostrarPeriodo()})});atualizarPrecos();mostrarPeriodo()});